49	const BASE_PREMIUMS: Record<string, number> = {
50	  sword: 100,
51	  amulet: 60,
52	  staff: 80,
53	  potion: 40,
54	  rune: 25,
55	  moonstone: 25,
56	};
57	
58	const PROCESSING_FEE_G = 5;
59	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1; // 10% surcharge on policy base
60	const COMPONENT_BLOCK_SIZE = 3;
61	const COMPONENT_BLOCK_PRICE_G = 60;
62	const CURSE_SURCHARGE_RATE = 0.5; // 50% of cursed item's base premium
63	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3; // 30% of enchanted item's base premium
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	
66	const COMPONENT_TYPES = ["rune", "moonstone"];
67	
68	const priceForComponentGroup = (count: number, unitPrice: number): number =>
69	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;
70	
71	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
72	
73	const isCursed = (item: Item): boolean => item.cursed === true;
74	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
75	const isHighlyEnchanted = (item: Item): boolean =>
76	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
77	
78	const surchargeFor = (items: Item[], predicate: (i: Item) => boolean, rate: number): number =>
79	  items.filter(predicate).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
80	
81	const LOYALTY_YEARS_THRESHOLD = 2;
82	const LOYALTY_DISCOUNT_RATE = 0.2; // 20% discount on policy base
83	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15; // 15% discount on policy base for contracts after the first
84	
85	const isLoyalCustomer = (customer: Customer): boolean =>
86	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
87	
88	const componentsBase = (items: Item[]): number =>
89	  COMPONENT_TYPES.reduce((sum, type) => {
90	    const count = items.filter((i) => i.type === type).length;
91	    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
92	  }, 0);
93	
94	const nonComponentsBase = (items: Item[]): number =>
95	  items.filter((i) => !isComponent(i)).reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
96	
97	const policyBaseFor = (items: Item[]): number =>
98	  componentsBase(items) + nonComponentsBase(items);
99	
100	const discountIf = (applies: boolean, base: number, rate: number): number =>
101	  applies ? base * rate : 0;
102	
103	const quotePremium = (items: Item[], customer: Customer, isFollowUpContract: boolean): number => {
104	  const policyBase = policyBaseFor(items);
105	  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
106	  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
107	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
108	  const loyaltyDiscount = discountIf(isLoyalCustomer(customer), policyBase, LOYALTY_DISCOUNT_RATE);
109	  const followUpDiscount = discountIf(isFollowUpContract, policyBase, FOLLOW_UP_CONTRACT_DISCOUNT_RATE);
110	  return Math.ceil(
111	    policyBase +
112	      curseSurcharge +
113	      enchantmentSurcharge +
114	      firstInsuranceSurcharge -
115	      loyaltyDiscount -
116	      followUpDiscount +
117	      PROCESSING_FEE_G,
118	  );
119	};
120	
121	const INSURANCE_VALUES: Record<string, number> = {
122	  sword: 1000,
123	  amulet: 600,
124	  staff: 800,
125	  potion: 400,
126	  rune: 250,
127	  moonstone: 250,
128	};
129	const DEDUCTIBLE_G = 100;
130	const CAP_MULTIPLIER = 2;
131	
132	interface PolicyState {
133	  items: Item[];
134	  remainingCap: number;
135	}
136	
137	const insuranceSumFor = (items: Item[]): number =>
138	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
139	
140	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
141	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
142	
143	const reimbursableAmountFor = (damage: Damage, item: Item): number =>
144	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
145	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
146	    : damage.amount;
147	
148	const openPolicy = (items: Item[]): PolicyState => ({
149	  items,
150	  remainingCap: CAP_MULTIPLIER * insuranceSumFor(items),
151	});
152	
153	const insuredItemFor = (policy: PolicyState, itemType: string): Item => {
154	  const item = policy.items.find((i) => i.type === itemType);
155	  if (!item) {
156	    throw new Error(`Damaged item not in policy: ${itemType}`);
157	  }
158	  return item;
159	};
160	
161	const payoutForDamageIn = (policy: PolicyState, damage: Damage): number => {
162	  if (damage.amount < 0) {
163	    throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
164	  }
165	  return reimbursableAmountFor(damage, insuredItemFor(policy, damage.itemType)) - DEDUCTIBLE_G;
166	};
167	
168	const countBy = <T>(xs: T[], key: (x: T) => string): Record<string, number> =>
169	  xs.reduce<Record<string, number>>((acc, x) => {
170	    const k = key(x);
171	    acc[k] = (acc[k] ?? 0) + 1;
172	    return acc;
173	  }, {});
174	
175	const assertDamagesMatchPolicy = (policy: PolicyState, incident: Incident): void => {
176	  const damageCounts = countBy(incident.damages, (d) => d.itemType);
177	  const insuredCounts = countBy(policy.items, (i) => i.type);
178	  for (const [type, count] of Object.entries(damageCounts)) {
179	    if (count > (insuredCounts[type] ?? 0)) {
180	      throw new Error(`More damages of type ${type} than insured items`);
181	    }
182	  }
183	};
184	
185	const settleClaim = (policy: PolicyState, incident: Incident): ClaimResult => {
186	  assertDamagesMatchPolicy(policy, incident);
187	  const rawPayout = incident.damages.reduce(
188	    (sum, d) => sum + payoutForDamageIn(policy, d),
189	    0,
190	  );
191	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
192	  policy.remainingCap -= payout;
193	  return { payout, remainingCap: policy.remainingCap };
194	};
195	
196	const assertKnownItemTypes = (items: Item[]): void => {
197	  const unknown = items.find((item) => !(item.type in BASE_PREMIUMS));
198	  if (unknown) {
199	    throw new Error(`Unknown item type: ${unknown.type}`);
200	  }
201	};
202	
203	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
204	  const policies: Record<number, PolicyState> = {};
205	
206	  const handleQuote = (step: QuoteStep, index: number): QuoteResult => {
207	    assertKnownItemTypes(step.items);
208	    const isFollowUpContract = Object.keys(policies).length > 0;
209	    const premium = quotePremium(step.items, scenario.customer, isFollowUpContract);
210	    policies[index] = openPolicy(step.items);
211	    return { premium };
212	  };
213	
214	  const handleStep = (step: Step, index: number): StepResult =>
215	    step.op === "quote" ? handleQuote(step, index) : settleClaim(policies[step.policy], step.incident);
216	
217	  return { results: scenario.steps.map(handleStep) };
218	};
